// Normalizes the raw HTTP response from whichever LLM provider was used
// into a common shape before Parse & Classify.
//
// Each provider wraps the model output differently:
//   'openai' (Responses API)     → output[0].content[0].text
//   'ollama' (Chat Completions, text model) → choices[0].message.content
//
// qwen3-vl may wrap its reasoning in <think>...</think> tags inside content.
// We strip those before passing to Parse & Classify.
//
// Output: { extracted_text: string }

const provider = 'ollama'; // hardcoded for local demo
const body = $input.item.json;

let extracted_text;

if (provider === 'ollama') {
  try {
    extracted_text = body.choices[0].message.content;
  } catch (e) {
    throw new Error('Unexpected Ollama response shape: ' + JSON.stringify(body));
  }
  // Strip <think>...</think> reasoning blocks (qwen3 family without format:json)
  extracted_text = extracted_text.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
} else {
  // Default: OpenAI Responses API
  try {
    extracted_text = body.output[0].content[0].text;
  } catch (e) {
    throw new Error('Unexpected OpenAI response shape: ' + JSON.stringify(body));
  }
}

if (!extracted_text) {
  throw new Error('Empty LLM response from provider "' + provider + '": ' + JSON.stringify(body));
}

return [{ json: { extracted_text } }];

// extracted_text is set by the upstream Normalize Response node.
// It holds the raw JSON string the LLM returned, regardless of provider.
const rawText = $json.extracted_text;

// Parse the JSON the model was instructed to return
let extracted;
try {
  extracted = JSON.parse(rawText);
} catch (e) {
  throw new Error('LLM returned non-JSON: ' + rawText);
}

const {
  invoice_number,
  vendor_name,
  invoice_date,
  due_date,
  total_amount,
  currency,
  line_items,
  notes,
  confidence
} = extracted;

// Required fields for review routing
const REQUIRED = ['invoice_number', 'vendor_name', 'total_amount'];
const missingFields = REQUIRED.filter(f => extracted[f] == null);

// Route to human review if confidence is not high OR any required field is missing
const needs_review = confidence !== 'high' || missingFields.length > 0;

// Build a human-readable reason for the review sheet
let review_reason = null;
if (needs_review) {
  const reasons = [];
  if (confidence !== 'high') reasons.push(`confidence=${confidence}`);
  if (missingFields.length > 0) reasons.push(`missing: ${missingFields.join(', ')}`);
  review_reason = reasons.join('; ');
}

// -- Uncomment to include detailed fields in Sheets output --
// const line_items_json = line_items ? JSON.stringify(line_items) : null;
// const emailData = $('Gmail Trigger').item.json;
// const binaryData = Object.values($input.item.binary || {})[0] || {};
// const attachment_filename = binaryData.fileName || binaryData.fileExtension
//   ? `${binaryData.fileName || 'attachment'}`
//   : 'unknown';

return [{
  json: {
    timestamp: new Date().toISOString(),
    vendor_name,
    invoice_number,
    invoice_date,
    due_date,
    total_amount,
    currency,
    confidence,
    notes,

    // Routing (required — do not remove)
    needs_review,

    // -- Uncomment to include detailed fields in Sheets output --
    // email_from: emailData.from,
    // email_subject: emailData.subject,
    // attachment_filename,
    // line_items_json,
    // review_reason,
    // raw_json: rawText
  }
}];
